import pytest
from datetime import datetime, timedelta, timezone

def test_schedule_appointment_exactly_24h_boundary_accepted(auth_client, available_slot_factory):
    slot_time = datetime.now(timezone.utc) + timedelta(hours=24, minutes=1)
    slot_id = available_slot_factory(slot_time)

    response = auth_client.post(
        "/appointments",
        json={"slot_id": slot_id}
    )

    assert response.status_code == 201, (
        f"On-boundary slot (24 h 1 min) must be accepted; got {response.status_code}"
    )
    assert response.json()["status"] == "booked"

import pytest
from datetime import datetime, timedelta, timezone

def test_schedule_appointment_exactly_at_24h_rejected(auth_client, available_slot_factory):
    slot_time = datetime.now(timezone.utc) + timedelta(hours=23, minutes=59)
    slot_id = available_slot_factory(slot_time)

    response = auth_client.post(
        "/appointments",
        json={"slot_id": slot_id}
    )

    assert response.status_code == 422, (
        f"Off-boundary slot (23 h 59 min) must be rejected; got {response.status_code}"
    )
